public class ConcatenationDemo {
 public static void main(String[] args) {
 String str = "university";
 for(int i=0; i<3; i++) {
 str += " Java"; // Creates new string each iteration
 }
 System.out.println(str); // Output: university Java Java Java
 }
}

public class StringPoolDemo {
 public static void main(String[] args) {
 String s1 = "university";
 String s2 = "university";
 String s3 = new String("university");

 System.out.println(s1 == s2); // true (same reference)
 System.out.println(s1 == s3); // false (different objects)
 System.out.println(s1.equals(s3)); // true (same content)

 String s4 = s3.intern();
 System.out.println(s1 == s4); // true (now pooled)
 }
}

public class ValueOfDemo {
 public static void main(String[] args) {
 int num = 42;
 boolean flag = true;
 Object obj = null;

 System.out.println(String.valueOf(num)); // "42"
 System.out.println(String.valueOf(flag)); // "true"
 System.out.println(String.valueOf(obj)); // "null"
 }
}

class Student {
 String name;
 int marks;

 Student(String n, int m) {
 name = n;
 marks = m;
 }

 @Override
 public String toString() {
 return "Student[" + name + ", " + marks + "]";
 }
}

public class ToStringDemo {
 public static void main(String[] args) {
 Student s = new Student("Alice", 85);
 System.out.println(s); // Implicitly calls toString()
 }
}
